import {format, formatDistanceToNow, differenceInDays, isWeekend, addDays} from 'date-fns';

export function formatDate(date: Date | string): string {
    const d = typeof date === 'string' ? new Date(date) : date;
    return format(d, 'MMM d, yyyy');
}

export function formatDateRange(startDate: Date | string, endDate: Date | string): string {
    const start = typeof startDate === 'string' ? new Date(startDate) : startDate;
    const end = typeof endDate === 'string' ? new Date(endDate) : endDate;

    if (start.getFullYear() === end.getFullYear()) {
        if (start.getMonth() === end.getMonth()) {
            return `${format(start, 'MMM d')} - ${format(end, 'd, yyyy')}`;
        }
        return `${format(start, 'MMM d')} - ${format(end, 'MMM d, yyyy')}`;
    }
    return `${format(start, 'MMM d, yyyy')} - ${format(end, 'MMM d, yyyy')}`;
}

export function countWorkdays(startDate: Date | string, endDate: Date | string): number {
    const start = typeof startDate === 'string' ? new Date(startDate) : startDate;
    const end = typeof endDate === 'string' ? new Date(endDate) : endDate;

    let count = 0;
    let current = new Date(start);
    while (current <= end) {
        if (!isWeekend(current)) {
            count++;
        }
        current = addDays(current, 1);
    }
    return count;
}

export function countDays(startDate: Date | string, endDate: Date | string): number {
    const start = typeof startDate === 'string' ? new Date(startDate) : startDate;
    const end = typeof endDate === 'string' ? new Date(endDate) : endDate;
    return differenceInDays(end, start) + 1;
}

export function relativeTime(date: Date | string): string {
    const d = typeof date === 'string' ? new Date(date) : date;
    return formatDistanceToNow(d, {addSuffix: true});
}

import {format, formatDistanceToNow, differenceInDays, isWeekend, addDays} from 'date-fns';
import Holidays from 'date-holidays';

export function formatDate(date: Date | string): string {
    const d = typeof date === 'string' ? new Date(date) : date;
    return format(d, 'MMM d, yyyy');
}

export function formatDateRange(startDate: Date | string, endDate: Date | string): string {
    const start = typeof startDate === 'string' ? new Date(startDate) : startDate;
    const end = typeof endDate === 'string' ? new Date(endDate) : endDate;

    if (start.getFullYear() === end.getFullYear()) {
        if (start.getMonth() === end.getMonth()) {
            return `${format(start, 'MMM d')} - ${format(end, 'd, yyyy')}`;
        }
        return `${format(start, 'MMM d')} - ${format(end, 'MMM d, yyyy')}`;
    }
    return `${format(start, 'MMM d, yyyy')} - ${format(end, 'MMM d, yyyy')}`;
}

export function countWorkdays(startDate: Date | string, endDate: Date | string): number {
    const start = typeof startDate === 'string' ? new Date(startDate) : startDate;
    const end = typeof endDate === 'string' ? new Date(endDate) : endDate;

    const hd = new Holidays('SK');
    let count = 0;
    let current = new Date(start);
    while (current <= end) {
        if (!isWeekend(current) && !hd.isHoliday(current)) {
            count++;
        }
        current = addDays(current, 1);
    }
    return count;
}

export function countDays(startDate: Date | string, endDate: Date | string): number {
    const start = typeof startDate === 'string' ? new Date(startDate) : startDate;
    const end = typeof endDate === 'string' ? new Date(endDate) : endDate;
    return differenceInDays(end, start) + 1;
}

export function relativeTime(date: Date | string): string {
    const d = typeof date === 'string' ? new Date(date) : date;
    return formatDistanceToNow(d, {addSuffix: true});
}

import type React from 'react';
import { Header } from '@/components/header';
import { Sidebar } from '@/components/sidebar';
import { getCurrentUser } from '@/lib/actions';
import { redirect } from 'next/navigation';

export default async function AuthenticatedLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const user = await getCurrentUser();
  if (!user) {
    redirect('/');
  }

  return (
    <div className="min-h-screen flex flex-col bg-background pt-[72px]">
      <Header />
      <div className="flex flex-1 w-full relative pt-6 pr-8 pb-6 pl-6">
        <div className="shrink-0 hidden sm:block sticky top-[96px] h-[calc(100vh-120px)] overflow-y-auto scrollbar-hide">
          <Sidebar className="border-none h-full" />
        </div>
        <main className="flex-1 min-w-0 flex flex-col">
          <div className="flex-1 bg-white rounded-[20px] shadow-[0px_8px_24px_#DCDEED] border border-gray-200/60 p-8 flex flex-col">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
}

import type React from 'react';
import { Header } from '@/components/header';
import { Sidebar } from '@/components/sidebar';
import { getCurrentUser } from '@/lib/actions';
import { redirect } from 'next/navigation';

export default async function AuthenticatedLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const user = await getCurrentUser();
  if (!user) {
    redirect('/');
  }

  return (
    <div className="min-h-screen flex flex-col bg-background pt-[72px]">
      <Header />
      <div className="flex flex-1 w-full relative p-3 sm:pt-6 sm:pr-8 sm:pb-6 sm:pl-6">
